import React, { useState, useEffect } from "react";
import "./App.css";
import mondaySdk from "monday-sdk-js";
import "monday-ui-react-core/dist/main.css";
import ListInputMod from "./modules/ListInputMod.js";
import { AlertBanner, AlertBannerText, AlertBannerLink } from "monday-ui-react-core";


const monday = mondaySdk();
const redirect_uri = "https://e47171547284.ngrok.app";
const client_id = "eb18d6836553020a3107559d979d31a8";
const client_secret = "ae0b0f705f2a9d99967c68fe1e61f308";

const App = () => {
  const [token, setToken] = useState(null);
  const [showBanner, setShowBanner] = useState(false);
  const [isViewOnly, setIsViewOnly] = useState(false);
  const [error, setError] = useState(null);

  useEffect(() => {
    setShowBanner(true);
    const storedToken = localStorage.getItem('mondayToken');
    if (storedToken) {
      setToken(storedToken);
      monday.setToken(storedToken);
      monday.api(`query { me { is_view_only }}`)
        .then(res => {
          if (res.data && res.data.me) {
            setIsViewOnly(res.data.me.is_view_only);
          } else {
            setError("Failed to fetch user permissions");
          }
        })
        .catch(err => {
          console.error("Error fetching user permissions:", err);
          setError("Failed to fetch user permissions");
        });
      console.log("Token retrieved from storage");
    } else {
      const urlParams = new URLSearchParams(window.location.search);
      const code = urlParams.get("code");
      if (code) {
        fetch('https://df5ac29b691e.ngrok.app/oauth/token', {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
          },
          body: JSON.stringify({
            client_id: client_id,
            client_secret: client_secret,
            code: code,
            redirect_uri: redirect_uri,
          }),
        })
        .then(response => {
          if (!response.ok) {
            throw new Error('OAuth token request failed');
          }
          return response.json();
        })
        .then(data => {
          if (data.access_token) {
            setToken(data.access_token);
            localStorage.setItem('mondayToken', data.access_token);
            monday.setToken(data.access_token);
            return monday.api(`query { me { is_view_only }}`)
          } else {
            throw new Error('No access token received');
          }
        })
        .then(res => {
          if (res.data && res.data.me) {
            setIsViewOnly(res.data.me.is_view_only);
          } else {
            throw new Error('Failed to fetch user permissions');
          }
          setShowBanner(true);
          window.history.replaceState({}, document.title, "/");
        })
        .catch(err => {
          console.error("Authentication error:", err);
          setError("Authentication failed. Please try again.");
          localStorage.removeItem('mondayToken');
        });
      } else {
        window.location.href = `https://auth.monday.com/oauth2/authorize?client_id=${client_id}&redirect_uri=${encodeURIComponent(redirect_uri)}&response_type=code`;
      }
    }
  }, []);

  return (
    <div className="App container">
      <div className="container">
        <div className="row">
          {showBanner && (
            <div className="col">
              <AlertBanner
                className="mb-3"
                onClose={() => setShowBanner(false)}
              >
                {error ? (
                  <AlertBannerText text={error} />
                ) : (
                  <>
                    <AlertBannerText text={`Welcome! You are ${isViewOnly ? 'in view-only mode' : 'in edit mode'}. Check out our `} />
                    <AlertBannerLink
                      href="https://rallyessentials.com/documentation/"
                      text="documentation"
                    />
                  </>
                )}
              </AlertBanner>
            </div>
          )}
        </div>
        <div className="row">
          <div className="col-12">
            <ListInputMod />
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
